def clean_working_directory(working_directory):
    """Cleans up scratch files generated by quantum chemical calculators."""
    if not working_directory:
        return
        
    wd = Path(working_directory)
    if not wd.exists():
        return
        
    wildcard_patterns = ["Gau-*"]
    file_names = ['energy', 'gradient', 'xtb', 'charges', 'xtbrestart', 'xtbtopo.mol']
    
    for pattern in wildcard_patterns:
        for file in wd.glob(pattern):
            if file.is_file():
                file.unlink()

    for filename in file_names:
        file = wd / filename
        if file.exists() and file.is_file():
            file.unlink()


class TMCGenerator:
    """Helper class to generate and initially scan conformers."""
    
    def __init__(self, calculator, scale=1.0, align=True, always_qc=False):
        self.cleaner = clean_geometry.TMCOptimizer(calculator=calculator)
        self.calculator = calculator
        self.scale = scale
        self.corrector = 0.2
        self.align = align
        self.always_qc = always_qc

    def sample_conformer(self, metal_complex, return_time=False):
        options = [0, 1]
        candidate_positions = []
        candidate_list = []
        energy_list = []
        
        gen_time_list = []
        scan_time_list = []
        gen_times = []
        scan_times = []
        
        for idx, option in enumerate(options):
            print(f"Embedding molecule {idx+1}/{len(options)} ...")
            gen_st = time.time()
            positions = embed.get_embedding(metal_complex, self.scale, option, self.align, use_random=True)
            if positions is not None:
                gen_et = time.time()
                candidate_positions.append(positions)
                gen_time_list.append(gen_et - gen_st)

        # Clean geometry and compute energy for each candidate position
        for candidate_position in candidate_positions:
            scan_st = time.time()
            tmp_metal_complex = metal_complex.copy()
            tmp_metal_complex.set_position(candidate_position)
            
            # Geometry optimization
            success = self.cleaner.clean_geometry(tmp_metal_complex, self.scale, self.always_qc) 
            scan_et = time.time()
            scan_time_list.append(scan_et - scan_st)
            
            ace_mol = tmp_metal_complex.get_molecule()
            energy = None

            candidate_list.append(ace_mol)
            # Temporarily remove the try/except to see the raw error
            print(f"Attempting xTB energy calculation for conformer...")
            energy = self.calculator.get_energy(ace_mol)

            # candidate_list.append(ace_mol)
            # try:
            #     energy = self.calculator.get_energy(ace_mol)
            # except Exception:
            #     energy = None
            #     scan_time_list[-1] = -1
                
            energy_list.append(energy if energy is not None else 1e6)

        print('energy', energy_list, '\n')
        
        if len(energy_list) == 0 or min(energy_list) == 1e6:
            return ([], [], []) if return_time else []
            
        # Use the most stable positions
        indices = np.argsort(energy_list)
        ace_mols = []
        for i in indices:
            if energy_list[i] < 1e6:
                candidate_list[i].energy = energy_list[i]
                ace_mols.append(candidate_list[i])
                gen_times.append(gen_time_list[i])
                scan_times.append(scan_time_list[i])

        return (ace_mols, gen_times, scan_times) if return_time else ace_mols


class MetallogenInterface:
    """Main interface for programmatic access to MetalloGen 3D generation."""

    def __init__(self, 
                 working_directory="./scratch", 
                 save_directory="./output", 
                 final_relax=True, 
                 num_conformer=10, 
                 calculator_type="xtb"):
        
        self.working_directory = working_directory
        self.save_directory = save_directory
        self.final_relax = final_relax
        self.num_conformer = num_conformer
        self.calculator_type = calculator_type.lower()
        
        self._setup_directories()
        self.calculator = self._initialize_calculator()

    def _setup_directories(self):
        """Creates required directories if they don't exist."""
        if self.save_directory:
            os.makedirs(self.save_directory, exist_ok=True)
        if self.working_directory:
            os.makedirs(self.working_directory, exist_ok=True)

    def _initialize_calculator(self):
        """Initializes the requested quantum chemical calculator dynamically."""
        if self.calculator_type == "xtb_gaussian":
            from MetalloGen.Calculator import gaussian
            calc = gaussian.Gaussian()
            calc.switch_to_xtb_gaussian()
            
        elif self.calculator_type == "xtb":
            from MetalloGen.Calculator import xtb
            calc = xtb.XTB()

        elif self.calculator_type == "xtb_s":
            from MetalloGen.Calculator import xtb_s
            calc = xtb_s.XTB_Standalone()

        elif self.calculator_type == "orca":
            from MetalloGen.Calculator import orca
            calc = orca.Orca()
            
        elif self.calculator_type == "gaussian":
            from MetalloGen.Calculator import gaussian
            calc = gaussian.Gaussian()
            
        else:
            raise ValueError(f"Invalid calculator specified: {self.calculator_type}")
            
        if self.working_directory:
            calc.change_working_directory(self.working_directory)
            
        return calc
    
