    def generate(self, smiles=None, input_directory=None):
        """
        Generates 3D structures for an organometallic complex.
        
        Provide EITHER a valid MSMILES string OR a path to an SDF/MOL input directory.
        """
        if smiles and "|" in smiles:
            metal_complex = om.get_om_from_modified_smiles(smiles)
            print(f"Loaded from MSMILES: {smiles}")
        elif input_directory:
            metal_complex = om.get_om_from_sdf(input_directory)
            print(f"Loaded from input directory: {os.path.basename(input_directory)}")
        else:
            raise ValueError("Please provide either a valid MSMILES string or an input MOL/SDF directory.")

        print(f"num atoms: {len(metal_complex.get_atom_list())}")
        print(f"chg: {metal_complex.chg}")
        print(f"mult: {metal_complex.multiplicity}")

        # Determine scaling factors based on requested number of conformers
        if self.num_conformer < 10:
            scales = [0.70, 0.80, 0.90, 1.00, 1.10]
        else:
            scales = [0.7 + ((0.8 + 0.1*(self.num_conformer-10))/(self.num_conformer-2))*k for k in range(int(self.num_conformer/2))]

        # 1. Generate Conformers
        total_ace_mols = []
        for scale in scales:
            print(f"\nGenerating conformer with scale {scale:.2f} ...")
            print("======================================================")
            generator = TMCGenerator(self.calculator, scale, align=True)
            ace_mols = generator.sample_conformer(metal_complex)
            total_ace_mols.extend(ace_mols)

        print("=======================================================")
        print(f"\nTotal {len(total_ace_mols)} conformers generated ...")
        
        if not total_ace_mols:
            print("No valid conformers generated. Exiting early.")
            return []

        # 2. Cluster Conformers
        print(f"\nClustering conformers ...")
        conformers = [ace_mol.get_coordinate_list() for ace_mol in total_ace_mols]
        atom_symbol = [atom.get_element() for atom in metal_complex.get_atom_list()]
        
        clusters, _ = clustering.cluster_conformers_butina(conformers, atom_symbol, cutoff=0.5, exclude_H=True)
        dif_ace_mols = [total_ace_mols[i[0]] for i in clusters]
        print(f"{len(dif_ace_mols)} conformers after clustering ...")

        if not self.final_relax:
            return dif_ace_mols

        # 3. Final Relaxation
        print("\nPerforming final relaxation ...")
        final_relaxed_mols = []
        num_successful = 0
        initial_hessian = None

        for i, ace_mol in enumerate(dif_ace_mols):
            if num_successful >= self.num_conformer:
                break
                
            print(f"\nRelaxing clustered conformer {i+1}/{len(dif_ace_mols)} ...")
            print("======================================================")
            
            original_energy = ace_mol.energy
            if original_energy == 1e6:
                continue
                
            print(f"Initial Energy: {original_energy}")
            
            try:
                # Run optimization
                self.calculator.optimize_geometry(ace_mol, 
                                                  file_name=f"final_relax_{num_successful}", 
                                                  initial_hessian=initial_hessian, 
                                                  save_directory=self.save_directory)
                normal_termination = True
            except Exception as e:
                print(f"Relaxation failed with error: {e}")
                normal_termination = False

            clean_working_directory(self.working_directory)

            if not normal_termination:
                print("Relaxation failed. Skipping to next conformer...")
                continue

            relaxed_energy = getattr(ace_mol, 'energy', 'Unknown')
            print(f"Relaxed Energy: {relaxed_energy}")
            
            # Save to disk
            content = f"{len(ace_mol.atom_list)}\n{ace_mol.chg}\t{ace_mol.multiplicity}\t{relaxed_energy}\n"
            for atom in ace_mol.atom_list:
                content += atom.get_content()

            if self.save_directory:
                file_base = f"result_{num_successful}"
                sdf_path = os.path.join(self.save_directory, f"{file_base}.sdf")
                
                try:
                    from rdkit import Chem
                    from rdkit.Chem import EditableMol, Mol
                    
                    # 1. Start fresh
                    emol = EditableMol(Mol())
                    atoms = ace_mol.get_atom_list()
                    
                    # 2. Add Atoms
                    for atom in atoms:
                        emol.AddAtom(Chem.Atom(atom.get_element()))
                    
                    # 3. Add Bonds from Adjacency Matrix
                    # adj_matrix is a 2D array where matrix[i][j] > 0 means a bond
                    adj = ace_mol.get_adj_matrix()
                    num_atoms = len(atoms)
                    for i in range(num_atoms):
                        for j in range(i + 1, num_atoms):
                            if adj[i][j] > 0:
                                # We use SINGLE to ensure RDKit doesn't crash on metal valency
                                emol.AddBond(i, j, Chem.rdchem.BondType.SINGLE)
                    
                    # 4. Finalize and set coords
                    rd_mol = emol.GetMol()
                    conf = Chem.Conformer(num_atoms)
                    for idx, atom in enumerate(atoms):
                        pos = atom.get_coordinates()
                        conf.SetAtomPosition(idx, (float(pos[0]), float(pos[1]), float(pos[2])))
                    rd_mol.AddConformer(conf)

                    # 5. Write to Disk
                    writer = Chem.SDWriter(sdf_path)
                    writer.write(rd_mol)
                    writer.close()
                    print(f"MANUAL SDF SUCCESS: {sdf_path}")
                        
                except Exception as e:
                    print(f"Manual SDF build failed: {e}. Falling back to XYZ.")
                    # Keep your old XYZ writing code here
                    content = f"{len(ace_mol.atom_list)}\n{ace_mol.chg}\t{ace_mol.multiplicity}\t{relaxed_energy}\n"
                    for atom in ace_mol.atom_list:
                        content += atom.get_content()
                    with open(os.path.join(self.save_directory, f"{file_base}.xyz"), "w") as f:
                        f.write(content)


            print("Relaxation success!\n")
            num_successful += 1
            final_relaxed_mols.append(ace_mol)

        print("=======================================================")
        print(f"\nTotal {num_successful} conformers successfully relaxed and saved.")
        return final_relaxed_mols
    
    def quick_view(self, index=0):
        """Interactive 3D visualization of the result."""
        import py3Dmol
        
        sdf_path = os.path.join(self.save_directory, f"result_{index}.sdf")
        xyz_path = os.path.join(self.save_directory, f"result_{index}.xyz")
        
        if os.path.exists(sdf_path):
            path, fmt = sdf_path, "sdf"
        else:
            path, fmt = xyz_path, "xyz"
            print("Warning: Visualizing XYZ. Bonds are inferred by distance.")

        with open(path, 'r') as f:
            data = f.read()

        view = py3Dmol.view(width=800, height=500)
        view.addModel(data, fmt)
        
        # Style: Stick & Sphere (Professional Look)
        # Note: radius 0.15 and scale 0.25 mimic the image you uploaded
        view.setStyle({'stick': {'radius': 0.15}, 'sphere': {'scale': 0.25}})
        
        # Aesthetic tweaks
        view.setBackgroundColor('#ffffff')
        view.zoomTo()
        return view.show()
    
    